INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'js', 10, 1, NULL, 'F. B. Meyer em Js 10:1', 'F. B. Meyer destaca a coerência doutrinária aplicada à vida cristã. Em Josué 10, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para justiça com misericórdia. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'F. B. Meyer', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'js', 11, 1, NULL, 'Gregório de Nissa em Js 11:1', 'Na leitura de Gregório de Nissa, vemos a leitura cristológica e eclesial da passagem. Josué 11 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Gregório de Nissa', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'js', 12, 1, NULL, 'John Flavel em Js 12:1', 'Segundo John Flavel, a piedade prática e a santificação do coração ilumina o sentido deste texto. Josué 12 mostra que providência divina na história do povo de Deus sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'John Flavel', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'js', 13, 1, NULL, 'E. M. Bounds em Js 13:1', 'Na leitura de E. M. Bounds, vemos a coerência doutrinária aplicada à vida cristã. Josué 13 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'E. M. Bounds', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'js', 14, 1, NULL, 'Atanásio em Js 14:1', 'Atanásio interpreta este versículo a partir de a leitura cristológica e eclesial da passagem. Em Josué 14, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Atanásio', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'js', 15, 1, NULL, 'Thomas Watson em Js 15:1', 'Thomas Watson destaca a piedade prática e a santificação do coração. Em Josué 15, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para santidade prática. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Thomas Watson', 'commentary', '#2E8B57', NOW()),
